# Manually fixed for correct Python syntax
"""
TDD Stage: variance_normalize
Compute adds variance calculation (square centered, REDUCE_ROW, add eps, rsqrt)
and full normalization (centered * rstd). No affine transform.
"""

import pytest
import torch
import ttnn


from .layer_norm import layer_norm


def pytorch_reference(torch_input):
    """PyTorch reference for this stage."""
    return torch.nn.functional.layer_norm(torch_input.to(torch.float32), [torch_input.shape[-1]]).to(torch.bfloat16)


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
        pytest.param((1, 1, 32, 128), id="1x1x32x128"),
        pytest.param((1, 1, 128, 64), id="1x1x128x64"),
        pytest.param((1, 1, 32, 256), id="1x1x32x256"),
        pytest.param((2, 1, 64, 64), id="2x1x64x64"),
    ],
)
def test_variance_normalize(device, shape):
    """Verify full normalization without affine: (x - mean) / sqrt(var + eps)."""
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)

    expected = pytorch_reference(torch_input)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=ttnn.TILE_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )

    ttnn_output = layer_norm(ttnn_input)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.05,
        atol=0.2,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
